import{_ as a,c as r,m as t,a as o,t as l,U as s,o as i}from"./chunks/framework.9QHaLlVJ.js";const g=JSON.parse('{"title":"编译原理","description":"","frontmatter":{"title":"编译原理"},"headers":[],"relativePath":"doc/编程语言/C/环境搭建/编译原理.md","filePath":"packages/doc/src/编程语言/C/环境搭建/编译原理.md","lastUpdated":1705159462000}'),c={name:"doc/编程语言/C/环境搭建/编译原理.md"},p={id:"frontmatter-title",tabindex:"-1"},_=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),n=s("<p>不管是C还是C++，这些易于人类阅读的高级语言，终究要进行编译，最终转换成机器可识别的二进制语言。</p><p>编译一般分为四个步骤：预处理-&gt;编译-&gt;汇编-&gt;链接。</p><ul><li>预处理</li></ul><p>预处理由预处理器（Preprocessor）处理，删除注释，引入头文件或者包，将宏定义内容在源文件（<em>.c、</em>.cpp等）中进行替换。</p><ul><li><p>编译 汇编阶段，编译器（Compiler）将经过预处理的高级语言翻译成机器可识别的汇编语言。</p></li><li><p>汇编</p></li></ul><p>由汇编器（Assembler），将汇编语言转换成机器语言（二进制文件），并进行重定位（Relocatable）。再由加载器（Loader）将重定向后的指令和数据放到内存指定位置。</p><ul><li>链接</li></ul><p>最终，由链接器（Linker）将多个可重定位的机器代码文件（包括库文件）连接到一起形成可执行文件。</p>",8);function d(e,m,f,h,u,C){return i(),r("div",null,[t("h1",p,[o(l(e.$frontmatter.title)+" ",1),_]),n])}const P=a(c,[["render",d]]);export{g as __pageData,P as default};
